/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp), then checks for EOF. */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token remaining = in.readToken();
    if (remaining != null)
      throw new ParseException("Unexpected token after expression: " + remaining);
    return result;
  }

  /** Parses:
    *   Exp ::= if Exp then Exp else Exp
    *         | let Def+ in Exp
    *         | map IdList to Exp
    *         | Term { BinOp Term }*   (left-associatively)
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF) {
      return parseIf();
    } else if (t == Lexer.LET) {
      return parseLet();
    } else if (t == Lexer.MAP) {
      return parseMap();
    } else {
      return parseBinaryExp();
    }
  }

  /** Parses: if Exp then Exp else Exp */
  private If parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    Token then = in.readToken();
    if (then != Lexer.THEN)
      throw new ParseException("Expected 'then' in if-expression, got: " + then);
    AST conseq = parseExp();
    Token els = in.readToken();
    if (els != Lexer.ELSE)
      throw new ParseException("Expected 'else' in if-expression, got: " + els);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let Def+ in Exp
    *   Def+ means one or more definitions, each of the form: Id := Exp ;
    */
  private Let parseLet() {
    in.readToken(); // consume 'let'
    List<Def> defs = new ArrayList<Def>();
    // Require at least one definition
    defs.add(parseDef());
    // Parse additional definitions while next token is an identifier (Variable)
    while (in.peek() instanceof Variable) {
      defs.add(parseDef());
    }
    Token inToken = in.readToken();
    if (inToken != Lexer.IN)
      throw new ParseException("Expected 'in' in let-expression, got: " + inToken);
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: Def ::= Id := Exp ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable))
      throw new ParseException("Expected identifier in definition, got: " + t);
    Variable var = (Variable) t;
    Token bind = in.readToken();
    if (bind != Lexer.BIND)
      throw new ParseException("Expected ':=' in definition, got: " + bind);
    AST rhs = parseExp();
    Token semi = in.readToken();
    if (semi != SemiColon.ONLY)
      throw new ParseException("Expected ';' in definition, got: " + semi);
    return new Def(var, rhs);
  }

  /** Parses: map IdList to Exp */
  private Map parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    Token to = in.readToken();
    if (to != Lexer.TO)
      throw new ParseException("Expected 'to' in map-expression, got: " + to);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: IdList ::= { PropIdList }
    *         PropIdList ::= Id { , Id }*
    * Returns zero or more Variable references.
    */
  private Variable[] parseIdList() {
    List<Variable> vars = new ArrayList<Variable>();
    Token t = in.peek();
    if (t instanceof Variable) {
      vars.add((Variable) in.readToken());
      while (in.peek() == Comma.ONLY) {
        in.readToken(); // consume ','
        Token next = in.readToken();
        if (!(next instanceof Variable))
          throw new ParseException("Expected identifier in id-list, got: " + next);
        vars.add((Variable) next);
      }
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: BinaryExp ::= Term { BinOp Term }*  (left-associatively) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    Token t = in.peek();
    while (t instanceof OpToken && ((OpToken) t).isBinOp()) {
      in.readToken(); // consume BinOp
      BinOp op = ((OpToken) t).toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
      t = in.peek();
    }
    return left;
  }

  /** Parses: Term ::= Unop Term
    *               | Factor { ( ExpList ) }
    *               | Empty
    *               | Int
    *               | Bool
    */
  private AST parseTerm() {
    Token t = in.peek();
    if (t instanceof OpToken && ((OpToken) t).isUnOp()) {
      in.readToken(); // consume unary operator
      UnOp op = ((OpToken) t).toUnOp();
      AST arg = parseTerm();
      return new UnOpApp(op, arg);
    } else if (t instanceof IntConstant) {
      return (IntConstant) in.readToken();
    } else if (t instanceof BoolConstant) {
      return (BoolConstant) in.readToken();
    } else if (t == EmptyConstant.ONLY) {
      in.readToken();
      return EmptyConstant.ONLY;
    } else {
      // Factor { ( ExpList ) }
      AST factor = parseFactor();
      if (in.peek() == LeftParen.ONLY) {
        in.readToken(); // consume '('
        AST[] args = parseExpList();
        Token rp = in.readToken();
        if (rp != RightParen.ONLY)
          throw new ParseException("Expected ')' after argument list, got: " + rp);
        return new App(factor, args);
      }
      return factor;
    }
  }

  /** Parses: Factor ::= ( Exp ) | Prim | Id */
  private AST parseFactor() {
    Token t = in.readToken();
    if (t == LeftParen.ONLY) {
      AST inner = parseExp();
      Token rp = in.readToken();
      if (rp != RightParen.ONLY)
        throw new ParseException("Expected ')' after parenthesized expression, got: " + rp);
      return inner;
    } else if (t instanceof PrimFun) {
      return (PrimFun) t;
    } else if (t instanceof Variable) {
      return (Variable) t;
    } else {
      throw new ParseException("Expected a factor (expression, primitive, or identifier), got: " + t);
    }
  }

  /** Parses: ExpList ::= { PropExpList }
    *         PropExpList ::= Exp { , Exp }*
    * Returns zero or more argument expressions.
    */
  private AST[] parseExpList() {
    List<AST> args = new ArrayList<AST>();
    if (in.peek() != RightParen.ONLY) {
      args.add(parseExp());
      while (in.peek() == Comma.ONLY) {
        in.readToken(); // consume ','
        args.add(parseExp());
      }
    }
    return args.toArray(new AST[0]);
  }
}
